      ))}
    </ul>
  );
}

import { useMemo } from "react";

export function Total({ xs }: { xs: number[] }) {
  const sum = useMemo(() => xs.reduce((a, b) => a + b, 0), [xs]);
  return <output>{sum}</output>;
}

